var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"늦은 시간까지 고생이 많군.","JPN":"遅くまでご苦労。","ENG":"It must be hard working so late.","TWN":"都這麼晚了，辛苦了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어님? 일정을 마치고 집무실로 돌아가신 줄 알았는데요?","JPN":"シニア？　スケジュールを終えて執務室にお帰りになったと思っていたのですが。","ENG":"Sir? I thought you returned to your office after finishing your schedules.","TWN":"Senior？我以為你完成日程後已經回到辦公室了呢？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"건틀렛 우승자에게 수여할 장비를 반출해야 하지 않나.","JPN":"ガントレットの優勝者に授与する装備を搬出する必要があるんだ｡","ENG":"I have to take out the gear to award the Gauntlet winner.","TWN":"呵呵，我還得把明天要頒發給優勝者的裝備拿出來。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"내일 오전 일찍 최고 관리자께서 이곳을 방문하신다고 하니, 미리 준비해 둘 수밖에.","JPN":"明日の午前、早い時間に最高管理者がこちらを訪問なさるとのことで、あらかじめ用意しないとな。","ENG":"The Supreme Administrator will be visiting early tomorrow morning, so I have no choice but to prepare beforehand.","TWN":"明天一早最高管理者就要來這裡，只能提前準備好。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그렇군요.","JPN":"なるほど。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"병기고의 장비 반출에도 시니어 권한이 필요하니…….","JPN":"兵器庫から装備を搬出する際にもシニアの権限が必要ですからね……","ENG":"Because a Senior authority is required to take out gear from the armory...","TWN":"從兵器庫調出裝備也需要高級許可權……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"자네도 그만하고 어서 퇴근하도록 해.","JPN":"君もその辺にして、早く退勤するように。","ENG":"You should go home.","TWN":"別磨蹭了，快去下班吧。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"내일부터 바빠질 지도 모르니.","JPN":"明日から忙しくなるかもしれない。","ENG":"We might be busy starting tomorrow.","TWN":"從明天開始可能會很忙。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>2급 관리자 확인. 리하르트 베르너.</color>","JPN":"<color=#ffd34c>2級管理者を確認。リヒャルト・ベルナー。</color>","ENG":"<color=#ffd34c>Class 2 Administrator confirmed. Richard Werner</color>","TWN":"<color=#ffd34c>2級管理員確認。理查·韋爾納。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>병기고 접근 승인.</color>","JPN":"<color=#ffd34c>兵器庫へのアクセス承認。</color>","ENG":"<color=#ffd34c>Access granted to the armory.</color>","TWN":"<color=#ffd34c>兵器庫訪問成功。</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"리하르트 베르너…….","JPN":"リヒャルト・ベルナー……","ENG":"Richard Werner...","TWN":"理查·韋爾納……"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대정화 전쟁에 지휘관으로 참전한 당신은 어느 전투에서 패전하여 큰 부상을 입었습니다.","JPN":"大浄化戦争に指揮官として参戦したあなたは、とある戦いにて敗れ、大怪我を負いました。","ENG":"You were gravely injured after losing a battle during the Grand Purification War where you participated as a commander.","TWN":"多年前作為大淨化戰爭的指揮官參戰，在某次戰鬥中敗北，身受重傷。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시간이 지나, 2급 관리자로 선별된 당신은 지난 날의 과오를 잊지 않겠다고 맹세했어요.","JPN":"時が流れ、2級管理者として選別されたあなたは去りゆく日の誤ちを忘れないと誓いました。","ENG":"As time passed, you vowed you'd never forget the mistakes you made in the past when you were appointed as a Class 2 Administrator.","TWN":"時光流逝，被選為2級管理員的你立下誓言，不會忘記過去所犯下的過錯。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 2급 관리자의 증표, <color=#ffd34c>시니어 코드</color>를 자기 의안에 심어두었죠.","JPN":"それで2級管理者の証、<color=#ffd34c>シニアコード</color>を自分の義眼に入れたのですね。","ENG":"So, you implanted the <color=#ffd34c>Senior Code</color>, the mark of a Class 2 Administrator, in your eye.","TWN":"所以，你將2級管理者的象徵，<color=#ffd34c>資深代碼</color>也植入了自己的義眼中。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전쟁에서 잃은 눈으로 전사한 이들을 주시하며, 결코 그들을 잊지 않겠다는 맹세.","JPN":"戦争で失った目で戦死した者たちを見つめ、決して彼らを忘れないという誓い。","ENG":"Your vow to see those who died in the battle with the eye you lost in the war, and never forget about them.","TWN":"用在戰爭中失去的眼睛注視著犧牲的戰士，發誓會永遠銘記著他們。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신의 그 굳은 맹세조차도 다른 정보로 덮어씌워 잊게 만들다니.","JPN":"あなたのその固い誓いさえも、他の情報で上書きして、忘れさせてしまうなんて。","ENG":"Even your determination is rewritten with other information.","TWN":"竟然能用其他資訊覆蓋你堅定的誓言。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정보 오염이라는 건 참으로 두렵군요.","JPN":"情報汚染というのはとても恐ろしいものです。","ENG":"Data corruption is truly scary.","TWN":"資訊污染真是可怕呢。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 나름대로 철저하게 행동했어요.","JPN":"あなたは、あなたなりに徹底した行動を取りました。","ENG":"In your own way, you acted meticulously.","TWN":"你做得很徹底。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신과 꽤 오래 일해왔는데, 코드 발동을 확인하지 못해 그걸 모방할 수 없었으니까요.","JPN":"あなたとはかなり長い間一緒に働いてきたんですが、コードの発動を確認できず、模倣することができませんでした。","ENG":"I have worked with you for quite some time, but I could never imitate how you activate your code for you never showed me.","TWN":"我和你共事了這麼久，卻一直沒能見到你啟動代碼，所以無法模仿它。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그 발동을 확인한 이상…….","JPN":"ですが、その発動を確認した以上……","ENG":"But since I have now seen how it's activated...","TWN":"不過現在……"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이제 이 머리는 더 이상 필요 없겠죠.","JPN":"もうこの頭は必要ありません。","ENG":"This head is no longer needed.","TWN":"既然見過了，這腦袋已經沒用了吧。"},"stage":{"bg":"GAME_LIFT","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요, 이게 알파트릭스에서 제작한 <color=#ffd34c>유사 얼터니움 리액터</color>.","JPN":"なるほど、これがアルファトリックスで製作した<color=#ffd34c>類似オルタニウムリアクター</color>。","ENG":"So, this is the <color=#ffd34c>pseudo-Alternium Reactor</color> produced by Alphatrix.","TWN":"原來如此，這是阿爾法崔克斯製作的<color=#ffd34c>黑化永恆之金電抗器</color>。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 이건 늑대의 테크 레벨5 무장, <color=#ffd34c>도르마</color>…….","JPN":"そしてこれはオオカミのテックレベル5武装、<color=#ffd34c>ドルマ</color>……","ENG":"And this is the Wolf's Tech Level 5 gear, <color=#ffd34c>Droma</color>...","TWN":"這是狼的技術等級5武裝，<color=#ffd34c>多爾瑪</color>……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};